$petatoe_json$::jsonb;
begin

  insert into public.localization_keys(translation_key,module,source_text,description,is_system,is_active)
  select x.translation_key,x.module,x.ar_text,'Imported from PETATOE local dictionaries (ELC Phase 2)',true,true
  from jsonb_to_recordset(payload) as x(translation_key text,module text,ar_text text,en_text text)
  on conflict (translation_key) do nothing;

  insert into public.localization_values(key_id,language_code,translated_text,status,version,approved_at)
  select k.id,'ar',x.ar_text,'approved',1,now()
  from jsonb_to_recordset(payload) as x(translation_key text,module text,ar_text text,en_text text)
  join public.localization_keys k on k.translation_key=x.translation_key
  where x.ar_text is not null and btrim(x.ar_text)<>''
  on conflict (key_id,language_code) do nothing;

  insert into public.localization_values(key_id,language_code,translated_text,status,version,approved_at)
  select k.id,'en',x.en_text,'approved',1,now()
  from jsonb_to_recordset(payload) as x(translation_key text,module text,ar_text text,en_text text)
  join public.localization_keys k on k.translation_key=x.translation_key
  where x.en_text is not null and btrim(x.en_text)<>''
  on conflict (key_id,language_code) do nothing;

  insert into public.localization_queue(translation_key,source_language,source_text,target_language,suggested_text,module,status)
  select x.translation_key,'ar',x.ar_text,'en',null,x.module,'pending'
  from jsonb_to_recordset(payload) as x(translation_key text,module text,ar_text text,en_text text)
  where x.en_text is null and x.ar_text is not null
  on conflict (source_text,source_language,target_language,module) do nothing;

  insert into public.localization_queue(translation_key,source_language,source_text,target_language,suggested_text,module,status)
  select x.translation_key,'ar',x.ar_text,'fil',null,x.module,'pending'
  from jsonb_to_recordset(payload) as x(translation_key text,module text,ar_text text,en_text text)
  where x.ar_text is not null
    and not exists (
      select 1 from public.localization_values v
      join public.localization_keys k on k.id=v.key_id
      where k.translation_key=x.translation_key and v.language_code='fil' and v.status='approved'
    )
  on conflict (source_text,source_language,target_language,module) do nothing;
end
$petatoe_batch$;

select 5::integer as completed_part, 220::integer as records_processed;
